package com.example.nofiltercoffee; import android.view.*; import android.widget.*; import androidx.recyclerview.widget.*; import java.util.*;
public class CategoryAdapter extends RecyclerView.Adapter<CategoryAdapter.VH>{public interface Listener{void onClick(String c);} ArrayList<String> list; Listener l; String selected="All"; public CategoryAdapter(ArrayList<String> list,Listener l){this.list=list;this.l=l;} public VH onCreateViewHolder(ViewGroup p,int v){return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_category,p,false));} public void onBindViewHolder(VH h,int pos){String c=list.get(pos); h.t.setText(c); h.t.setBackgroundResource(c.equals(selected)?R.drawable.bg_chip_selected:R.drawable.bg_chip_unselected); h.t.setTextColor(h.t.getResources().getColor(c.equals(selected)?R.color.espresso_bg:R.color.cream)); h.t.setOnClickListener(v->l.onClick(c));} public int getItemCount(){return list.size();} public void setSelectedCategory(String c){selected=c;notifyDataSetChanged();} static class VH extends RecyclerView.ViewHolder{TextView t; VH(View v){super(v);t=v.findViewById(R.id.txtCategory);}}}
